import threading
import time
import random

class VulnerableBank:
    def __init__(self):
        self.balance = 1000
        self.lock = threading.Lock()

    def withdraw_vulnerable(self, amount):
        # TOCTOU: check then act without lock
        if self.balance >= amount:
            time.sleep(0.001)  # Simulates processing delay
            self.balance -= amount
            return True
        return False

    def withdraw_safe(self, amount):
        with self.lock:
            if self.balance >= amount:
                self.balance -= amount
                return True
            return False

def exploit_race(bank, amount, num_threads):
    results = {'success': 0, 'fail': 0}
    def try_withdraw():
        if bank.withdraw_vulnerable(amount):
            results['success'] += 1
        else:
            results['fail'] += 1
    threads = [threading.Thread(target=try_withdraw) for _ in range(num_threads)]
    for t in threads: t.start()
    for t in threads: t.join()
    return results

print('Race Condition Exploit Demo')
print('='*60)

print('\n--- Vulnerable (no locking) ---')
bank = VulnerableBank()
bank.balance = 1000
results = exploit_race(bank, 900, 5)
print(f'Initial balance: 1000')
print(f'Withdrawal amount: 900 x 5 threads')
print(f'Successful withdrawals: {results["success"]}')
print(f'Final balance: {bank.balance}')
print(f'Money created from thin air: {results["success"] * 900 - 1000}')

print('\n--- Safe (with locking) ---')
